sys_script_include.script:
var task_privacy = Class.create();
task_privacy.prototype = {
    initialize: function() {
		this.userInfo = new UserInfoScripts();
		// DFCT0011930 - DFCT0011967 - DFCT0011988 - DFCT0011990 DFCT0011994
		var userHasRole = this.userInfo.UserHasRole('x_153465_discovert.tasker_application_admin');
		this.isUserTaskerApplicationAdmin = userHasRole==true || userHasRole=='true';
		this.orgTable = 'x_153465_discovert_discover_office_hierarchy';
		this.memberTable = 'x_153465_discovert_discover_office_members';
    },

	// DFCT0011930 - this function does not check the role, but only checks for membership
	userIsInOrgStructureForOU: function(ouID, userId){
		var userIsGHA = false;
		var orgPrivacy;
		var topOU;
		var queryGHAOUs;
		var countOUs = 0;
		var grOUs = new GlideRecordSecure(this.orgTable);
		var gaOUs = new GlideAggregate(this.memberTable);

		// userId is optional, so check for it
		if(!userId || userId == undefined || userId == "undefined"){
			userId = gs.getUserID();
		}
		queryGHAOUs = "office_member=" + userId;
		if(grOUs.get(ouID)){
			// DFCT0011966
			orgPrivacy = grOUs.u_top_ou.u_organizational_privacy;
			topOU = grOUs.getValue("u_top_ou");
			// if private our restricted, GHA must be in org structure
			if(orgPrivacy=="ou_private" || orgPrivacy=="restricted"){
				// DFCT0011913
				queryGHAOUs = queryGHAOUs + '^discover_office_hierarchy.u_top_ou=' + topOU;
			} else {
				// open OU  DFCT0011913
				queryGHAOUs = queryGHAOUs + 
					"^discover_office_hierarchy.u_top_ou.u_organizational_privacy!=ou_private" + 
					"^discover_office_hierarchy.u_top_ou.u_organizational_privacy!=restricted" + 
					'^discover_office_hierarchy.u_top_ou=' + topOU;
			}
		}

		// if the count of offices for this user is true, then return all open OUs for the user
		gaOUs.addEncodedQuery(queryGHAOUs);
		gaOUs.addAggregate("COUNT");
		gaOUs.query();
		if(gaOUs.next()){
			countOUs = gaOUs.getAggregate('COUNT');
		}
		if(countOUs>0){
			userIsGHA = true;
		}
		return userIsGHA;		

	},

	// DFCT0011843 - this gets all top OUs where the user is a Task Administrator
	getUserTopOUTaskAdminOrExec: function() {
		var userId = gs.getUserID();
		var offices = [];
		offices = this._getUserOUTaskAdminOrExec(userId, true, true);
		return offices;
	},

	// DFCT0011843 - this gets all OUs where the user is a Task Administrator
	getUserOUTaskAdminOrExec: function() {
		var userId = gs.getUserID();
		var offices = [];
		offices = this._getUserOUTaskAdminOrExec(userId, false, true);
		return offices;
	},

	// DFCT0011843 - this is called by both functions above to return values based on how it is called
	_getUserOUTaskAdminOrExec: function (userId, topOnly, includeExternal){
		var offices = [];
		var grOUs = new GlideRecordSecure(this.orgTable);
		var grMembers = new GlideRecordSecure(this.memberTable);		
		var grAllOUs;
		var allOrgStructureOUs;

		// get the open offices
		offices = this._getAdminOrExecOpenOUs(userId, topOnly, includeExternal);

		// the first query needs to get all offices for the user.  There are cases where the user is an Administrator, but only in a sub ou
		var queryAdminOUsNotOpen = "office_memberDYNAMIC90d1921e5f510100a9ad2572f2b477fe" +
			"^discover_office_hierarchy.active=true" +
			"^is_global_tasking_authority=true" +
			"^ORis_task_executive=true" + 
			"^ORis_tasker_application_admin=true" + 
			"^discover_office_hierarchy.u_top_ou.u_organizational_privacy=ou_private" + 
			"^ORdiscover_office_hierarchy.u_top_ou.u_organizational_privacy=restricted";

		if(!includeExternal){
			queryAdminOUsNotOpen = "discover_office_hierarchy.u_top_ou.u_external_flag=false" + "^" + queryAdminOUsNotOpen;
		}

		grMembers.addEncodedQuery(queryAdminOUsNotOpen);
		grMembers.query();
		while(grMembers.next()){
			var grMemberOrg = new GlideRecordSecure(this.orgTable);
			if(grMemberOrg.get(grMembers.discover_office_hierarchy)){
				if(topOnly){
					// add the top OU instead of the current OU
					offices.push(grMemberOrg.getValue('u_top_ou'));
				} else {
					allOrgStructureOUs = "active=true^u_top_ou=" + grMemberOrg.getValue('u_top_ou');
					// reset glide record
					grAllOUs = new GlideRecordSecure(this.orgTable);
					grAllOUs.addEncodedQuery(allOrgStructureOUs);
					grAllOUs.query();
					while(grAllOUs.next()){
						offices.push(grAllOUs.getUniqueValue());
					}			
				}				
			}
		}
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		}
		return offices;
	},

	// DFCT0011843 - this is called by both functions above to return values based on how it is called
	// NOTE: if we want to change open to be just offices where the Admin is a member of it, this is the query we would change for dynamic filters
	_getAdminOrExecOpenOUs: function(userId, topOnly, includeExternal){
		var offices = [];
		var countOUs = 0;
		var grOUs = new GlideRecordSecure(this.orgTable);
		var gaOUs = new GlideAggregate(this.memberTable);

		// get all members of all open office structures and all members of office structures this user is a member of
		var queryAdminOrExecOpenOUs = "office_memberDYNAMIC90d1921e5f510100a9ad2572f2b477fe" +
			"^discover_office_hierarchy.active=true" +
			"^discover_office_hierarchy.u_top_ou.u_organizational_privacy!=ou_private" + 
			"^discover_office_hierarchy.u_top_ou.u_organizational_privacy!=restricted";
		// tasker application Admin sees all open, so only add the additional filter if NOT application admin
		if(!this.isUserTaskerApplicationAdmin){
			queryAdminOrExecOpenOUs = queryAdminOrExecOpenOUs +
				"^is_global_tasking_authority=true^ORis_task_executive=true";
		}

		var queryAllOpenOUs = "u_top_ou.u_organizational_privacy!=ou_private" + 
			"^u_top_ou.u_organizational_privacy!=restricted";

		if(!includeExternal){
			queryAdminOrExecOpenOUs = "discover_office_hierarchy.u_external_flag=false" + "^" + queryAdminOrExecOpenOUs;
			queryAllOpenOUs = "u_external_flag=false" + "^" + queryAllOpenOUs;
		}

		// if the count of offices for this user is true, then return all open OUs for the user
		gaOUs.addEncodedQuery(queryAdminOrExecOpenOUs);
		gaOUs.addAggregate("COUNT");
		gaOUs.query();
		if(gaOUs.next()){
			countOUs = gaOUs.getAggregate('COUNT');
		}
		if(countOUs>0){
			grOUs.addEncodedQuery(queryAllOpenOUs);
			grOUs.query();
			while(grOUs.next()){
				if(topOnly){
					// add the top OU instead of the current OU
					offices.push(grOUs.getValue('u_top_ou'));
				} else {
					offices.push(grOUs.getUniqueValue());
				}
			}
		}
		return offices;
	},

	// STRY0139614 - STRY0139615 - STRY0139616 - STRY0139617 
	// This function is used in dynamnic filters
	// The current object is the record of the field the fitler applies to
	// do not use this function outside of dynamic filters
	getAllUsersAdminsCanTask: function(){
		var returnNone=false;
		// string for member sys_ids, default to get no users
		var memArr = [];
		var primary_ou = this._getPrimaryOUforAnyRecordType(current);
		var allTopOus= [];
		var top_ou = this._getTopOU(primary_ou);
		// using gliderecord secure here will return only people this user can see
		var grMembers = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		// get all members of all open office structures and all members of office structures this user is a member of
		var queryAllOpenOUMembers = "discover_office_hierarchy.u_top_ou.u_organizational_privacy!=ou_private" + 
			"^discover_office_hierarchy.u_top_ou.u_organizational_privacy!=restricted";


		var userCanTaskQuery = "";
		var recordPrivacyLevel = current.getValue("u_privacy");
		switch(recordPrivacyLevel){
			case "open": case "": case undefined: case null:
				// set query to return usrs in all open orgs
				userCanTaskQuery = queryAllOpenOUMembers;

				// DFCT0011913 - find all of the orgStructures a User is in
				allTopOus = this.userInfo.getAllTopOUsForUser(gs.getUserID());
				userCanTaskQuery = userCanTaskQuery + "^discover_office_hierarchy.u_top_ouIN" + allTopOus.join(",");
				break;
			case "restricted": 
				// get all members of the restricted  org structure of the Primary Office
				userCanTaskQuery = "discover_office_hierarchy.u_top_ou=" + top_ou;
				break;

			case "ou_private":
				// get all members of the private org structure of the Primary Office
				userCanTaskQuery = "discover_office_hierarchy.u_top_ou=" + top_ou;

				// future, will need to allow this case to be broader than just primary office to support crossover private tasking

				break;


			// future, here need to account for private tasks where only members of the task tree are loaded
			// case "private":

			default:
				// return no items
				returnNone=true;
		}
		if(!returnNone){
			grMembers.addEncodedQuery(userCanTaskQuery);
			grMembers.query();
			while(grMembers.next()){
				memArr.push(grMembers.getValue("office_member"));
			}
			if(memArr.length==0){
				memArr.push("none");
			}
		}
		return memArr;
	},

	// DFCT0011843 - DFCT0011926 - pass information down from screen instead of pulling from current record
	retrieveAdminTaskOUsPrivacyFiltered: function(primary_office, recordPrivacy){
		var offices = [];
		offices = this.getUserOUTaskAdminOrExec();
		// returns intersection of offices found and privacy flitered by Primary Office
		// DFCT0011926 - pass information down from screen instead of pulling from current record
		offices = this._getOfficesPrivacyFitleredByPrimaryOffice(offices, primary_office, recordPrivacy);
		return offices;  
	},

	// DFCT0011926 - pass information down from screen instead of pulling from current record
	retrieveTaskOUsPrivacyFiltered: function(userId, primary_office, recordPrivacy){
		var offices = [];
		var taskingScripts = new tasking_System_Settings_Scripts();
		offices = taskingScripts.retrieveTaskOUs(userId);
		// returns intersection of offices found and privacy flitered by Primary Office
		// DFCT0011926 - pass information down from screen instead of pulling from current record
		offices = this._getOfficesPrivacyFitleredByPrimaryOffice(offices, primary_office, recordPrivacy);
		return offices;  
	},

	// DFCT0011850 - add primary office and record privacy
	retrieveTemplateOUsPrivacyFiltered: function (userID, primary_office, recordPrivacy, template_level, template_ou){
		var offices = [];
		var taskingScripts = new tasking_System_Settings_Scripts();
		offices = taskingScripts.retrieveTemplateOUs(userID, template_level, template_ou);
		// returns intersection of offices found and privacy flitered by Primary Office
		// DFCT0011849 - pass information down from screen instead of pulling from current record
		offices = this._getOfficesPrivacyFitleredByPrimaryOffice(offices, primary_office, recordPrivacy);
		return offices;  
	},

	// This method is called from a dynamic filter and needs the current object to have a Primary Office field
	// this method calls the method previously used, then fitlers based on the new privacy settings
	getMyOUTaskManagersPrivacyFiltered: function() {
		var offices = [];
		// get the list of offices this user manages
		var taskingScripts = new tasking_System_Settings_Scripts();
		offices = taskingScripts.getMyOUTaskManagers();
		// returns intersection of offices found and privacy flitered by Primary Office
		offices = this._getOfficesPrivacyFitleredByPrimaryOffice(offices);
		return offices;  
	},

	getPermissiveOUsPrivacyFiltered: function() {
		var offices = [];
		var privacyFilterOffices = [];
		var taskingScripts = new tasking_System_Settings_Scripts();
		offices = taskingScripts.getPermissiveOUs();
		// returns intersection of offices found and privacy flitered by Primary Office
		offices = this._getOfficesPrivacyFitleredByPrimaryOffice(offices);
		return offices;  
	},

	// DFCT0011849 - pass information down from screen instead of pulling from current record
	// most times this is called, nothing is passed to primary_office
	// DFCT0012060 - NOTE: when no Primary Office is set, return all of the OUs the user could select
	//                     the calling functions pass in the offices and the array received is used as the fl
	_getOfficesPrivacyFitleredByPrimaryOffice: function (offices, primary_office, record_privacy){
		var privacyFilterOffices = [];
		var primary_ou;
		var recordPrivacyLevel;
		if(primary_office && primary_office != undefined && primary_office != "" && primary_office != null && primary_office != null){
			primary_ou = primary_office;
		} else {
			// get the task record values
			primary_ou = this._getPrimaryOUforAnyRecordType(current);
		}
		if(record_privacy){
			recordPrivacyLevel = record_privacy;
		} else {
			recordPrivacyLevel = current.getValue("u_privacy");	
		}

		if(primary_ou && primary_ou != undefined && primary_ou != "" && primary_ou != null && primary_ou != "null"){
			privacyFilterOffices = this._getPrivacyFilteredOffice(primary_ou, recordPrivacyLevel);
			// undefined is returned if the Primary Office is not set for the task record
			// only return the intersecting offices with the privacy filter
			var au = new global.ArrayUtil();
			// DFCT0011912  - STRY0139617 update for this story to handle case where Tasking is Open
			if(offices.length==1 && offices[0]=='all'){
				offices = privacyFilterOffices;
			} else {
				offices = au.intersect(offices, privacyFilterOffices);
			}
		}
		return offices;	
	},

	// this is called only from filters and will have a current object to pull Primary Office from
	// DFCT0011850 - add primary office, but only for this call ignore for others
	_getPrivacyFilteredOffice: function(primary_office, recordPrivacy){
		var returnNone=false;
		var privacyOffices = [];
		var grPrivateOUs = new GlideRecordSecure("x_153465_discovert_discover_office_hierarchy");
		var queryAllOpenOUs = "u_top_ou.u_organizational_privacy!=ou_private" + 
			"^u_top_ou.u_organizational_privacy!=restricted";

		var officesCanTaskQuery = "";
		// DFCT0011850 - add primary office
		var primary_ou = primary_office;
		var recordPrivacyLevel = recordPrivacy; 
		if(primary_ou==undefined && current != null){
			primary_ou = this._getPrimaryOUforAnyRecordType(current);
		}
		if(recordPrivacyLevel==undefined && current != null){
			recordPrivacyLevel = current.getValue("u_privacy");
		}
		// DFCT0012002 - not sure why, but this needed to be converted to string
		recordPrivacyLevel = recordPrivacyLevel.toString();
		var top_ou = this._getTopOU(primary_ou);
		switch(recordPrivacyLevel){
			case "open": case "": case undefined: case null:				
				// set query to return usrs in all open orgs
				// DFCT0011913
				officesCanTaskQuery = queryAllOpenOUs + "^u_top_ou=" + top_ou;
				break;
			case "restricted": 
				// get all members of the restricted  org structure of the Primary Office
				officesCanTaskQuery = "u_top_ou=" + top_ou;
				break;

			case "ou_private":
				// get all members of the private org structure of the Primary Office
				officesCanTaskQuery = "u_top_ou=" + top_ou;
				// future, will need to allow this case to be broader than just primary office to support crossover private tasking
				break;
			// future, here need to account for private tasks where only members of the task tree are loaded
			// case "private":
			default:
				// return no items
				returnNone=true;
		}
		if(!returnNone){
			grPrivateOUs.addEncodedQuery(officesCanTaskQuery);
			grPrivateOUs.query();
			while(grPrivateOUs.next()){
				privacyOffices.push(grPrivateOUs.getUniqueValue());
			}
			if(privacyOffices.length==0){
				privacyOffices.push("none");
			}
		}
		return privacyOffices;
	},

	_getTopOU: function (ouId){
		var topOU = "";
		var grOfficeOU = new GlideRecordSecure("x_153465_discovert_discover_office_hierarchy");
		// in dynamnic filters, current object is the record of the field the fitler applies to
		if(grOfficeOU.get(ouId)){
			topOU = grOfficeOU.getValue("u_top_ou");
		}
		return topOU;
	},

	_getPrimaryOUforAnyRecordType: function(gr){
		var primary_ou_id = gr.getValue("primary_office");
		var u_primary_ou_id = gr.getValue("u_primary_office");
		var primary_office_id = primary_ou_id || u_primary_ou_id;
		return primary_office_id;
	},

	getTopOUOrganizationalPrivacy: function(ouID){
		var organizationalPrivacy = "open";
		// DFCT0011800 - this is used to determine permissions, using GlideRecord Secure causes an ACL Loop
		var grOfficeOU = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
		if(grOfficeOU.get(ouID)){
			// DFCT0011847 now get Top OU
			var topOUId = grOfficeOU.getValue("u_top_ou");
			// DFCT0011800 - this is used to determine permissions, using GlideRecord Secure causes an ACL Loop
			var grTopOU = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
			if(grTopOU.get(topOUId)){
				organizationalPrivacy = grTopOU.getValue("u_organizational_privacy");
			}
		}
		return organizationalPrivacy;
	},

	// NOTE: this should move into UserInfo or Oganizational Scripts after initial release
	isUserInOrgStructure: function (ouID, userID){
		var answer = false;
		// get the top ID and use it to see if user is in the org structure
		// DFCT0011800 - this is used to determine permissions, using GlideRecord Secure causes an ACL Loop
		var grOfficeOU = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
		if(grOfficeOU.get(ouID)){
			// DFCT0011847 - now get Top OU
			var topOUId = grOfficeOU.getValue("u_top_ou");

			//Query organizational unit members to see if the user is a member
			// RAJ - STRY0011695 - change to use Glide Aggregate
			var grMembers = new GlideAggregate('x_153465_discovert_discover_office_members');
			grMembers.addEncodedQuery("discover_office_hierarchy.u_top_ou=" + topOUId + "^office_member=" + userID);
			// RAJ - STRY0011695 - change to use Glide Aggregate
			grMembers.addAggregate('COUNT');
			grMembers.query();

			if(grMembers.next()){
				// RAJ - STRY0011695 - change to use Glide Aggregate
				if (grMembers.getAggregate('COUNT') > 0){
					answer = true;
				}
			}
		}
		return answer;
	},

	// DFCT0011928 - templates check if user is in any open org structure before showing templates
	isUserInAnyOpenOrgStructure: function (userID){
		var answer = false;

		//Query organizational unit members to see if the user is a member of any open offices
		var grMembers = new GlideAggregate('x_153465_discovert_discover_office_members');
		grMembers.addEncodedQuery("discover_office_hierarchy.u_top_ou.u_organizational_privacy!=restricted^discover_office_hierarchy.u_top_ou.u_organizational_privacy!=ou_private^office_member=" + userID);
		grMembers.addAggregate('COUNT');
		grMembers.query();
		if(grMembers.next()){
			if (grMembers.getAggregate('COUNT') > 0){
				answer = true;
			}
		}
		return answer;
	},

	// DFCT0011928 - Templates require different access than all other records in the app.  
	// admins should not be able to see open templates unless they are in at least one open ou structure
	// DFCT0011930 - DFCT0011967 - DFCT0011988 - DFCT0011990 DFCT0011994
	userCanAccessTemplate: function(officeId){
		return this.userCanAccessOU(officeId);
	},

	// DFCT0011930 - DFCT0011967 - DFCT0011988 - DFCT0011990 DFCT0011994
	userCanAccessOU: function(officeId){
		var currentUserId = gs.getUserID();
		var isOpenOrg = false;
		var organizationalPrivacy;
		var userCanReadOU = false;
		organizationalPrivacy = this.getTopOUOrganizationalPrivacy(officeId);
		isOpenOrg = organizationalPrivacy == 'open';
		if(!officeId || officeId==''){
			userCanReadOU=true;
		} else if(this.isUserTaskerApplicationAdmin){
			userCanReadOU=true;
		} else if(isOpenOrg){
			userCanReadOU=this.isUserInAnyOpenOrgStructure(currentUserId);
		} else {
			userCanReadOU = this.isUserInOrgStructure(officeId,currentUserId);
		}
		return userCanReadOU;
	},

    type: 'task_privacy'
};
